var minMoves = function(nums, k) {
    const pos = [];
    for (let i = 0; i < nums.length; i++) if (nums[i] === 1) pos.push(i);
    const g = pos.map((p, i) => p - i);
    const n = g.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + g[i];
    let best = null;
    for (let l = 0; l <= n - k; l++) {
        const r = l + k - 1;
        const m = l + Math.floor((k - 1) / 2);
        const leftCount = m - l;
        const rightCount = r - m;
        const median = g[m];
        const leftSum = prefix[m] - prefix[l];
        const rightSum = prefix[r + 1] - prefix[m + 1];
        const cost = (median * leftCount - leftSum) + (rightSum - median * rightCount);
        if (best === null || cost < best) best = cost;
    }
    return best;
};
